mapper.select:

select

  distinct




      ${column.aliasedEscapedColumnName}




    ,



from litemall_goods




  order by ${example.orderByClause}


select



      ${column.aliasedEscapedColumnName}




    ,



from litemall_goods




  order by ${example.orderByClause}

limit 1

select g.id, g.goods_sn, g.name, g.category_id, g.brand_id, g.gallery, g.keywords, g.brief, g.is_on_sale, g.status, g.sort_order, g.pic_url, g.share_url, g.is_new, g.is_hot, g.is_special_price, g.special_price, g.is_presale, g.unit, g.counter_price, g.retail_price, g.add_time, g.update_time, g.deleted from litemall_goods g
inner join clothing_goods_scene cgs on g.id = cgs.goods_id and cgs.scene_id = #{sceneId}
where g.status = 'published' and g.deleted = 0
and g.category_id = #{categoryId}
and g.brand_id = #{brandId}
and g.is_hot = #{isHot}
and g.is_new = #{isNew}
and (g.keywords like concat('%', #{keyword}, '%') or g.name like concat('%', #{keyword}, '%'))
order by
(case when g.name = #{keyword} then 100 when g.name like concat(#{keyword}, '%') then 80 when g.name like concat('%', #{keyword}, '%') then 50 when g.keywords like concat(#{keyword}, '%') then 30 when g.keywords like concat('%', #{keyword}, '%') then 10 else 0 end) desc, g.sort_order desc, g.add_time desc
g.sort_order desc, g.add_time desc
g.${sort} ${order}
